// ============================================================
// VALIDATE & PREPARE TRANSACTION
// Calculates totals, generates transaction ID, validates payload
// ============================================================
try {
  const input = $input.first().json;

  // Validate tenant
  const tenant = input.tenant;
  if (!tenant || !tenant.sheets_id || !tenant.business_name) {
    throw new Error('Missing tenant configuration');
  }

  // Validate customer
  const customer = input.customer;
  if (!customer || !customer.id || !customer.phone) {
    throw new Error('Missing customer data');
  }

  // Validate items
  const items = Array.isArray(input.items) ? input.items : [];
  if (items.length === 0) throw new Error('No items in transaction');

  // Clean and calculate items
  const cleanItems = items.map(it => {
    const qty = parseFloat(it.qty ?? it.quantity ?? 1) || 1;
    const unitPrice = parseFloat(it.unit_price ?? it.price ?? 0) || 0;
    return {
      name: String(it.name ?? 'item').trim(),
      qty: qty,
      unit_price: unitPrice,
      line_total: +(qty * unitPrice).toFixed(2),
      metadata: it.metadata || {}
    };
  });

  // Calculate totals
  const subtotal = +cleanItems.reduce((s, it) => s + it.line_total, 0).toFixed(2);
  const deliveryFee = parseFloat(input.delivery_fee ?? 0) || 0;
  const discountPct = parseFloat(input.discount_pct ?? 0) || 0;
  const discountAmount = +(subtotal * discountPct / 100).toFixed(2);
  const finalPrice = +(subtotal + deliveryFee - discountAmount).toFixed(2);

  // Tax calculation
  const taxPct = parseFloat(tenant.tax_pct ?? 0) || 0;
  const taxAmount = +(finalPrice * taxPct / 100).toFixed(2);
  const totalWithTax = +(finalPrice + taxAmount).toFixed(2);

  // Generate Transaction ID (internal, not dependent on Apps Script)
  const now = new Date();
  const datePart = now.toISOString().slice(0,10).replace(/-/g,'').slice(2);
  const randPart = Math.floor(Math.random() * 9000) + 1000;
  const prefixMap = {
    order: 'ORD',
    booking: 'BKG',
    service_request: 'SRV',
    purchase: 'PUR'
  };
  const prefix = prefixMap[input.transaction_type] || 'TXN';
  const transactionId = `${prefix}_${datePart}_${randPart}`;
  const invoiceId = tenant.enable_invoices ? `INV_${datePart}_${randPart}` : '';

  const orderDate = now.toISOString().slice(0,19).replace('T', ' ');
  const totalQty = cleanItems.reduce((s, it) => s + it.qty, 0);
  const itemsText = cleanItems.map(it =>
    `${it.name} ×${it.qty} = ${it.line_total} ${tenant.currency}`
  ).join('\n');

  return {
    json: {
      // Tenant passthrough
      tenant: tenant,

      // IDs
      transaction_id: transactionId,
      invoice_id: invoiceId,
      transaction_type: input.transaction_type || 'order',

      // Customer
      customer_id: customer.id,
      customer_name: customer.name,
      customer_phone: customer.phone,
      remote_jid: customer.remote_jid || `${customer.phone}@s.whatsapp.net`,

      // Transaction details
      address_or_location: input.address_or_location || '',
      scheduled_at: input.scheduled_at || null,
      payment_method: input.payment_method || 'cash',
      notes: input.notes || '',
      coupon_code: input.coupon_code || '',
      custom_fields: input.custom_fields || {},

      // Items
      items: cleanItems,
      items_count: cleanItems.length,
      items_text: itemsText,
      total_qty: totalQty,

      // Money
      subtotal: subtotal,
      delivery_fee: deliveryFee,
      discount_pct: discountPct,
      discount_amount: discountAmount,
      final_price: finalPrice,
      tax_pct: taxPct,
      tax_amount: taxAmount,
      total_with_tax: totalWithTax,
      currency: tenant.currency,

      // Meta
      order_date: orderDate,
      created_at: now.toISOString()
    }
  };
} catch (e) {
  throw new Error('VALIDATE_AND_PREPARE failed: ' + e.message);
}

// ============================================================
// BUILD CONFIRMATION MESSAGES (Customer + Admin)
// Adapts message style based on transaction_type
// ============================================================
const o = $input.first().json;

const itemsLines = o.items.map(it =>
  `• ${it.name} × ${it.qty} = ${it.line_total} ${o.currency}`
).join('\n');

const paymentLabel = {
  cash: '💵 كاش عند الاستلام',
  online: '💳 دفع إلكتروني',
  transfer: '💰 تحويل بنكي',
  card: '💳 بطاقة ائتمانية',
  wallet: '📱 محفظة إلكترونية'
}[o.payment_method] || `💰 ${o.payment_method}`;

// Build customer message based on transaction type
const typeLabels = {
  order: { title: 'تم تأكيد طلبك', emoji: '✅', addr_label: '📍 العنوان', time_label: '🛵 وقت التوصيل المتوقع: 30-60 دقيقة' },
  booking: { title: 'تم تأكيد حجزك', emoji: '📅', addr_label: '📍 المكان', time_label: o.scheduled_at ? `🕐 الموعد: ${o.scheduled_at}` : '' },
  service_request: { title: 'تم استلام طلبك', emoji: '🛠️', addr_label: '📍 الموقع', time_label: '⏳ هنتواصل معاك في أقرب وقت' },
  purchase: { title: 'تم تأكيد شرائك', emoji: '🛒', addr_label: '📍 عنوان الشحن', time_label: '📦 وقت التوصيل: 2-5 أيام عمل' }
};
const labels = typeLabels[o.transaction_type] || typeLabels.order;

let customerMsg = `${labels.emoji} *${labels.title} بنجاح!*\n\n`;
customerMsg += `🧾 رقم العملية: *${o.transaction_id}*\n`;
customerMsg += `👤 ${o.customer_name}\n\n`;
customerMsg += `📋 *التفاصيل:*\n${itemsLines}\n\n`;
customerMsg += `💰 *الحساب:*\n`;
customerMsg += `- المجموع: ${o.subtotal} ${o.currency}\n`;
if (o.delivery_fee > 0) customerMsg += `- التوصيل: ${o.delivery_fee} ${o.currency}\n`;
if (o.discount_amount > 0) customerMsg += `- الخصم: -${o.discount_amount} ${o.currency}\n`;
if (o.tax_amount > 0) customerMsg += `- الضريبة (${o.tax_pct}%): ${o.tax_amount} ${o.currency}\n`;
customerMsg += `- *الإجمالي: ${o.total_with_tax || o.final_price} ${o.currency}*\n\n`;
if (o.address_or_location) customerMsg += `${labels.addr_label}: ${o.address_or_location}\n`;
customerMsg += `${paymentLabel}\n`;
if (o.notes) customerMsg += `📝 ملاحظات: ${o.notes}\n`;
if (labels.time_label) customerMsg += `\n${labels.time_label}\n`;
customerMsg += `\nنشكر ثقتك في *${o.tenant.business_name}* 🌹`;

// Admin notification
let adminMsg = `🆕 *${labels.title} جديد — ${o.transaction_id}*\n\n`;
adminMsg += `👤 ${o.customer_name} | 📱 ${o.customer_phone}\n`;
if (o.address_or_location) adminMsg += `${labels.addr_label}: ${o.address_or_location}\n`;
adminMsg += `\n${itemsLines}\n\n`;
adminMsg += `💰 الإجمالي: *${o.total_with_tax || o.final_price} ${o.currency}*\n`;
adminMsg += `${paymentLabel}\n`;
if (o.notes) adminMsg += `📝 ${o.notes}\n`;
adminMsg += `\n🕐 ${o.order_date}`;

return {
  json: {
    ...o,
    customer_msg: customerMsg,
    admin_msg: adminMsg
  }
};

// ============================================================
// RETURN SUCCESS RESPONSE TO CALLING AGENT
// ============================================================
const o = $input.first().json;

return {
  json: {
    success: true,
    transaction_id: o.transaction_id,
    invoice_id: o.invoice_id || '',
    transaction_type: o.transaction_type,
    final_price: o.total_with_tax || o.final_price,
    currency: o.currency,
    items_count: o.items_count,
    message: `تم حفظ العملية ${o.transaction_id} بنجاح بإجمالي ${o.total_with_tax || o.final_price} ${o.currency}. تم إبلاغ العميل والإدارة.`
  }
};
